args.sparql:
PREFIX wd: <http://www.wikidata.org/entity/>
PREFIX wdt: <http://www.wikidata.org/prop/direct/>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>

SELECT ?sister_char ?sister_char_label
WHERE {
  ?sister_char wdt:P161 wd:Q552580 ;
               wdt:P3373 wd:Q1606948 .
  ?sister_char rdfs:label ?sister_char_label .
  FILTER (LANG(?sister_char_label) = "en")
}

PREFIX wd: <http://www.wikidata.org/entity/>
PREFIX wdt: <http://www.wikidata.org/prop/direct/>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>

SELECT ?sister ?sisterLabel ?actress ?actressLabel
WHERE {
  ?sister wdt:P3373 wd:Q1606948 ;
          wdt:P21 wd:Q6581072 ;
          wdt:P3842 wd:Q207375 ;
          wdt:P161 ?actress .
  ?sister rdfs:label ?sisterLabel .
  ?actress rdfs:label ?actressLabel .
  FILTER (LANG(?sisterLabel) = "en")
  FILTER (LANG(?actressLabel) = "en")
}
